        if parent_aspace_ptr == 0 {
            return Err(MmError::InvalidAddress);
        }
        let aspace = unsafe { &mut *(parent_aspace_ptr as *mut Sv39AddressSpace) };
        aspace.handle_cow_fault(VirtAddr(fault_addr))
    }

    /// 销毁用户地址空间：递归释放所有用户页帧和页表帧。
