            _ => Err(SignalError::InvalidTimer),
        }
    }

    fn timer_clock(&self, which : usize, monotonic_ns : u128) -> SignalResult<u128> {
        match which {
            ITIMER_REAL => Ok(monotonic_ns),
            ITIMER_VIRTUAL => Ok(self.user_cpu_ns),
            ITIMER_PROF => Ok(self.total_cpu_ns),
            _ => Err(SignalError::InvalidTimer),
        }
    }
