    head: usize,
    len: usize,
    read_open: bool,
    write_open: bool,
    /// 读端 fd 引用计数；归零时 `read_open` 置 false。
    read_refs: usize,
    /// 写端 fd 引用计数；归零时 `write_open` 置 false。
    write_refs: usize,
