                   if meta.node_type != VfsNodeType::File {
                       return Err(VfsError::NotAFile);
                   }
                   Ok(meta)
               }).map_err(vfs_error_to_errno)?;
    usize::try_from(meta.size).map_err(|_| ErrNo::EINVAL)
}

