                             .keys()
                             .next()
                             .cloned()
                             .expect("page cache: no entries to evict");
        let idx = self.index
                      .remove(&victim_key)
                      .unwrap();
        self.frames[idx].key = None;
        self.frames[idx].dirty = false;
        idx
    }

