//! 用户态 bring-up 各阶段共享的 ELF 装载、spawn 与串行等待逻辑。

extern crate alloc;

use alloc::string::String;
use alloc::vec;
use alloc::vec::Vec;

use mm::api::kernel_bringup::{LoadProgramError, LoadedElf, PrepareUserStackError};
use runtime::logging::*;

/// glibc / musl 根卷前缀。
pub const LIBC_PREFIXES : &[&str] = &["/glibc",
//"/musl"
];

/// bring-up 阶段一次用户态启动：`program` 为待装载 ELF，`argv` 为完整参数（busybox 时
/// `argv[0]` 须为 applet 名，如 `"sh"` / `"timeout"`，而非 busybox 路径）。
pub struct BringupCommand {
    pub program : &'static str,
    pub argv : &'static [&'static str],
}

/// 按 [`BringupCommand`] 串行执行：装载 `program` → spawn → wait → reap。
pub fn run_one_bringup_command(log_tag : &str, cmd : &BringupCommand) {
    if cmd.argv.is_empty() {
        warn!("[{log_tag}] skip cmd program={}: empty argv",
              cmd.program);
        return;
    }
    run_one_elf_argv(log_tag, cmd.program, cmd.argv);
}

/// 基于已装载 ELF 创建用户任务，并在用户栈上写入 `argv` / `envp`（与 `execve`
/// 布局一致）。
pub fn spawn_user_task_from_loaded_elf_with_argv(loaded : &LoadedElf,
                                                 argv : &[&str],
                                                 envp : &[&str])
                                                 -> Result<task::TaskId, PrepareUserStackError> {
    let sp = mm::kernel_mm::prepare_elf_user_stack(loaded, argv, envp)?;
    let (argc, argv_ptr, envp_ptr) = initial_entry_args(sp, argv.len());
    let spec =
        task::user_task_from_loaded_elf(loaded).with_initial_user_sp(sp)
                                               .with_initial_user_args(argc, argv_ptr, envp_ptr);
    Ok(task::spawn_user_task(spec))
}

/// 根据 `prepare_elf_user_stack` 返回的栈顶，推算 argc/argv/envp 指针（与
/// `execve` 用户栈布局一致）。
fn initial_entry_args(sp : usize, argc : usize) -> (usize, usize, usize) {
    let word = core::mem::size_of::<usize>();
    let argv = sp + word;
    let envp = argv + (argc + 1) * word;
    (argc, argv, envp)
}

/// 串行执行单个 ELF 或 shebang 脚本：装载 → spawn → wait → reap；失败或跳过仅 `warn`。
pub fn run_one_elf_argv(log_tag : &str, elf_path : &str, argv : &[&str]) {
    let _ = run_one_elf_argv_exit(log_tag, elf_path, argv);
}

/// 串行执行单个 ELF/脚本并返回退出码；装载/创建失败返回 `None`。
pub fn run_one_elf_argv_exit(log_tag : &str, elf_path : &str, argv : &[&str]) -> Option<isize> {
    #[cfg(feature = "vfs-bridge")]
    if let Err(e) = warn_if_path_missing(log_tag, elf_path) {
        warn!("[{log_tag}] skip path={elf_path}: rootfs check: {e:?}");
        return None;
    }

    let load_result = load_program_without_timer_preemption(elf_path, argv);
    let (loaded, final_argv) = match load_result {
        Ok(pair) => pair,
        Err(e) => {
            warn!("[{log_tag}] skip load path={elf_path}: {e:?}");
            return None;
        }
    };

    let final_argv_refs : Vec<&str> = final_argv.iter()
                                                .map(String::as_str)
                                                .collect();
    info!("[{log_tag}] spawn path={elf_path} entry_pc={:#x} satp={:#x} argv={final_argv:?}",
          loaded.entry_pc, loaded.satp);
    let envp = libc_envp_for_path(elf_path);
    let tid = match spawn_user_task_from_loaded_elf_with_argv(&loaded, &final_argv_refs, &envp) {
        Ok(t) => t,
        Err(e) => {
            warn!("[{log_tag}] skip spawn path={elf_path}: {e:?}");
            mm::kernel_mm::drop_user_aspace(loaded.user_aspace_ptr);
            return None;
        }
    };

    cred::on_user_task_spawned(tid);

    #[cfg(feature = "vfs-bridge")]
    vfs::cwd::on_user_task_spawned_for_elf(tid, elf_path, &final_argv_refs);
    #[cfg(feature = "vfs-bridge")]
    vfs::mount_ns::on_user_task_spawned(tid);

    task::wait_for_task_exit(tid);
    let exit_code = task::reap_exited_task(tid).map(|e| {
                                                   drop_reaped_task_runtime_resources(&e);
                                                   e.exit_code
                                               })
                                               .unwrap_or(-1);

    let (purge, stray_exited) = task::purge_all_user_processes();
    for exited in &stray_exited {
        drop_reaped_task_runtime_resources(exited);
    }
    if purge.killed_tasks > 0 {
        warn!("[{log_tag}] script cleanup killed {} stray user task(s) after path={elf_path}",
              purge.killed_tasks);
    }
    trace!("[{log_tag}] script cleanup summary killed={} reaped={} after path={elf_path}",
           purge.killed_tasks,
           purge.reaped_processes);
    if purge.reaped_processes > 0 {
        trace!("[{log_tag}] script cleanup reaped {} exited process(es) after path={elf_path}",
               purge.reaped_processes);
    }

    syscall::log_thread_bringup_stats_summary();

    trace!("[{log_tag}] END path={elf_path} exit_code={exit_code}");
    Some(exit_code)
}

/// 回收已退出任务的用户地址空间与 syscall 侧挂接资源。
fn drop_reaped_task_runtime_resources(exited : &task::ExitedTask) {
    let aspace = exited.trap_frame
                       .as_ref()
                       .map(|frame| frame.user_aspace_ptr())
                       .unwrap_or(0);
    syscall::drop_reaped_task_runtime_resources(exited.id, aspace);
}


/// 按 ELF 路径前缀选择 glibc/musl 的 `LD_LIBRARY_PATH` 与 `PATH`。
fn libc_envp_for_path(path : &str) -> Vec<&'static str> {
    if path.starts_with("/glibc/") {
        // LTP 脚本用 `. test.sh` 相对 PATH 加载库；须先于 /glibc/test.sh（lua 包装），
        // 否则 tst_resm 等会落到 PATH 里的 C 二进制并 fork/wait，attach 段与后台 job 组合会卡死。
        vec!["LD_LIBRARY_PATH=/glibc/lib",
             "PATH=/glibc/ltp/testcases/bin:/glibc/ltp/testcases/lib:/glibc:/bin:/usr/bin:/sbin:/\
              usr/sbin"]
    } else if path.starts_with("/musl/") {
        vec!["LD_LIBRARY_PATH=/musl/lib",
             "PATH=/musl/ltp/testcases/bin:/musl/ltp/testcases/lib:/musl:/bin:/usr/bin:/sbin:/usr/\
              sbin"]
    } else {
        Vec::new()
    }
}

/// 串行执行 `/{prefix}/basic/{name}`，argv 仅含 ELF 自身路径。
pub fn run_one_basic_elf(log_tag : &str, prefix : &str, name : &str) {
    let elf_path = alloc::format!("{prefix}/basic/{name}");
    let argv : Vec<&str> = vec![elf_path.as_str()];
    run_one_elf_argv(log_tag, elf_path.as_str(), &argv);
}

/// 串行执行 shell 脚本：等价于 `busybox sh <脚本>`（见 [`BringupCommand`] 自行写 timeout 等）。
pub fn run_one_busybox_script(log_tag : &str, script_path : &str) {
    let busybox_path = match mm::api::executable::busybox_path_for_script(script_path) {
        Some(path) => path,
        None => {
            warn!("[{log_tag}] skip script={script_path}: unknown libc prefix");
            return;
        }
    };

    #[cfg(feature = "vfs-bridge")]
    if let Err(e) = warn_if_path_missing(log_tag, script_path) {
        warn!("[{log_tag}] skip script={script_path}: rootfs check: {e:?}");
        return;
    }

    run_one_elf_argv(log_tag, busybox_path, &["sh",
                                              script_path]);
}

/// 装载 ELF 期间屏蔽全局中断，避免定时器抢占打断页表/地址空间临界区。
fn load_program_without_timer_preemption(path : &str,
                                         argv : &[&str])
                                         -> Result<(LoadedElf, Vec<String>), LoadProgramError> {
    let state = platform::interrupt::read_global_interrupt_state().ok();
    let _ = platform::interrupt::disable_global_interrupt();
    let result = mm::kernel_mm::load_program_from_path(path, argv);
    if let Some(state) = state {
        let _ = platform::interrupt::restore_global_interrupt_state(state);
    }
    result
}

#[cfg(feature = "vfs-bridge")]
fn warn_if_path_missing(log_tag : &str, path : &str) -> Result<(), vfs::api::VfsError> {
    use vfs::api::SingleRootReadView;
    let view = vfs::root::read_view();
    if !view.exists(path)? {
        warn!("[{log_tag}] MISSING path: {path}");
        return Err(vfs::api::VfsError::NotFound);
    }
    Ok(())
}

//! 全局栈式物理帧分配器（单核 `UniprocessorSafeCell`）：`FrameId` 为
//! **PPN**，与 4 KiB 物理页一一对应。
//!
//! 调用方须保证 `init_frame_allocator` 传入的 PPN 区间落在
//! **内核可安全分配/回收** 的 RAM 内；本模块不校验与页表或设备的重叠。

#![no_std]
#![allow(static_mut_refs)]
extern crate alloc;

use alloc::vec::Vec;

use api_v0::{FrameAllocError, FrameAllocResult, FrameMemStats, PhysicalFrameAllocator};
use mm_api::addr::{PhysPageNum, PAGE_SIZE};
use wateros_base::addr::BasePPN;
use wateros_base::sync::UniprocessorSafeCell;
use arch::interrupt::{
    disable_global_interrupt, read_global_interrupt_state, restore_global_interrupt_state,
    ArchInterruptState,
};

use core::mem::MaybeUninit;
use core::sync::atomic::{AtomicBool, Ordering};

struct FrameAllocatorInterruptGuard {
    state : ArchInterruptState,
}

impl FrameAllocatorInterruptGuard {
    fn new() -> Self {
        let state = read_global_interrupt_state()
            .expect("read global interrupt state for frame allocator guard");
        disable_global_interrupt().expect("disable global interrupt for frame allocator guard");
        Self { state }
    }
}

impl Drop for FrameAllocatorInterruptGuard {
    fn drop(&mut self) {
        restore_global_interrupt_state(self.state)
            .expect("restore global interrupt state for frame allocator guard");
    }
}

fn with_frame_allocator<R>(f : impl FnOnce(&mut StackFrameAllocator) -> R) -> R {
    let _guard = FrameAllocatorInterruptGuard::new();
    f(&mut get_frame_allocator_cell().exclusive_access())
}

/// 临时的 LIFO 栈式帧分配器：
/// - `init(start_ppn, end_ppn)` 产生 free-list；
/// - `alloc_frame()` 从栈顶 pop；
/// - `dealloc_frame()` push 回栈（顺序回放）。
///
/// 注意：该实现未做“重复释放/未分配校验”，属于早期阶段可接受的简化。
///
/// 空闲帧来自两段语义：尚未动过的连续高段 `[start_ppn,
/// next_novel)`（惰性下推）， 以及显式回收栈 `recycled`。不在 `init` 时把整段
/// PPN 推入 `Vec`，避免大内存下撑爆内核 heap。
pub struct StackFrameAllocator {
    recycled : Vec<PhysPageNum>,
    allocated : Vec<bool>,
    ref_counts : Vec<usize>,
    start_ppn : usize,
    end_ppn : usize,
    /// 仍可从连续区分配的第一页号上界（不包含）；初始为 `end_ppn`。
    next_novel : usize,
}

impl StackFrameAllocator {
    /// 构造空分配器；须再调用 [`Self::init`] 方可从 PPN 区间取帧。
    pub fn new() -> Self {
        Self { recycled : Vec::new(),
               allocated : Vec::new(),
               ref_counts : Vec::new(),
               start_ppn : 0,
               end_ppn : 0,
               next_novel : 0 }
    }

    /// 将可用帧限制为半开区间 `[start_ppn,
    /// end_ppn)`（PPN）；会清空回收栈并重置惰性上界。
    pub fn init(&mut self, start_ppn : BasePPN, end_ppn : BasePPN) {
        self.recycled
            .clear();
        self.start_ppn = start_ppn.val;
        self.end_ppn = end_ppn.val;
        self.next_novel = end_ppn.val;
        self.allocated
            .clear();
        self.allocated
            .resize(end_ppn.val.saturating_sub(start_ppn.val), false);
        self.ref_counts
            .clear();
        self.ref_counts
            .resize(end_ppn.val.saturating_sub(start_ppn.val), 0);
    }

    #[inline]
    fn index(&self, frame : PhysPageNum) -> Option<usize> {
        if frame.0 < self.start_ppn || frame.0 >= self.end_ppn {
            None
        } else {
            Some(frame.0 - self.start_ppn)
        }
    }

    /// 只读内存池统计：总帧 = 区间大小；空闲 = 回收栈 + 未分配连续段。
    pub fn mem_stats(&self) -> FrameMemStats {
        let total_frames = self.end_ppn.saturating_sub(self.start_ppn);
        let novel_free = self.next_novel.saturating_sub(self.start_ppn);
        let free_frames = self.recycled.len().saturating_add(novel_free);
        FrameMemStats {
            total_frames,
            free_frames: free_frames.min(total_frames),
            page_bytes: PAGE_SIZE,
        }
    }
}

impl PhysicalFrameAllocator for StackFrameAllocator {
    type FrameId = PhysPageNum;

    fn alloc_frame(&mut self) -> FrameAllocResult<Self::FrameId> {
        while let Some(p) = self.recycled.pop() {
            let Some(idx) = self.index(p) else {
                log::warn!("[frame-allocator] drop invalid recycled ppn={:#x} range=[{:#x},{:#x})",
                           p.0,
                           self.start_ppn,
                           self.end_ppn);
                continue;
            };
            if self.allocated[idx] {
                log::warn!("[frame-allocator] drop duplicate recycled ppn={:#x}",
                           p.0);
                continue;
            }
            self.allocated[idx] = true;
            self.ref_counts[idx] = 1;
            return Ok(p);
        }
        if self.next_novel > self.start_ppn {
            self.next_novel -= 1;
            let p = PhysPageNum(self.next_novel);
            let idx = self.next_novel - self.start_ppn;
            if self.allocated[idx] {
                log::warn!("[frame-allocator] novel ppn already allocated ppn={:#x}",
                           p.0);
                return Err(FrameAllocError::InvalidFrame);
            }
            self.allocated[idx] = true;
            self.ref_counts[idx] = 1;
            return Ok(p);
        }
        Err(FrameAllocError::OutOfMemory)
    }

    fn dealloc_frame(&mut self, frame : Self::FrameId) -> FrameAllocResult<()> {
        let Some(idx) = self.index(frame) else {
            log::warn!("[frame-allocator] invalid dealloc ppn={:#x} range=[{:#x},{:#x})",
                       frame.0,
                       self.start_ppn,
                       self.end_ppn);
            return Err(FrameAllocError::InvalidFrame);
        };
        if frame.0 < self.next_novel || !self.allocated[idx] || self.ref_counts[idx] == 0 {
            log::warn!("[frame-allocator] invalid dealloc ppn={:#x} next_novel={:#x} \
                        allocated={} ref_count={}",
                       frame.0,
                       self.next_novel,
                       self.allocated[idx],
                       self.ref_counts[idx]);
            return Err(FrameAllocError::InvalidFrame);
        }
        if self.ref_counts[idx] > 1 {
            self.ref_counts[idx] -= 1;
            return Ok(());
        }
        self.ref_counts[idx] = 0;
        self.allocated[idx] = false;
        self.recycled
            .push(frame);
        Ok(())
    }
}

impl StackFrameAllocator {
    pub fn inc_ref(&mut self, frame : PhysPageNum) -> FrameAllocResult<usize> {
        let Some(idx) = self.index(frame) else {
            log::warn!("[frame-allocator] invalid inc_ref ppn={:#x} range=[{:#x},{:#x})",
                       frame.0,
                       self.start_ppn,
                       self.end_ppn);
            return Err(FrameAllocError::InvalidFrame);
        };
        if !self.allocated[idx] || self.ref_counts[idx] == 0 {
            log::warn!("[frame-allocator] inc_ref on unallocated ppn={:#x} allocated={} \
                        ref_count={}",
                       frame.0,
                       self.allocated[idx],
                       self.ref_counts[idx]);
            return Err(FrameAllocError::InvalidFrame);
        }
        self.ref_counts[idx] = self.ref_counts[idx].saturating_add(1);
        Ok(self.ref_counts[idx])
    }

    pub fn ref_count(&self, frame : PhysPageNum) -> FrameAllocResult<usize> {
        let Some(idx) = self.index(frame) else {
            return Err(FrameAllocError::InvalidFrame);
        };
        if !self.allocated[idx] || self.ref_counts[idx] == 0 {
            return Err(FrameAllocError::InvalidFrame);
        }
        Ok(self.ref_counts[idx])
    }
}

// ===== 全局单例（安全单核）=====

static mut FRAME_ALLOCATOR : MaybeUninit<UniprocessorSafeCell<StackFrameAllocator>> =
    MaybeUninit::uninit();
static FRAME_ALLOCATOR_READY : AtomicBool = AtomicBool::new(false);

// `FRAME_ALLOCATOR` 仅在首次 `init_frame_allocator` 中 `write`
// 一次，之后只读；与 `READY` 发布顺序配对。
fn get_frame_allocator_cell() -> &'static UniprocessorSafeCell<StackFrameAllocator> {
    assert!(FRAME_ALLOCATOR_READY.load(Ordering::Acquire),
            "frame allocator not initialized: call init_frame_allocator() first");
    unsafe { &*FRAME_ALLOCATOR.as_ptr() }
}

